import{_ as t,o as e,c as i,a2 as l}from"./chunks/framework.CL9FnezB.js";const u=JSON.parse('{"title":"GTDamage 快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"gtdamage/index.md","filePath":"gtdamage/index.md","lastUpdated":1783543150000}'),r={name:"gtdamage/index.md"};function d(o,a,h,n,s,c){return e(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="gtdamage-快速开始" tabindex="-1">GTDamage 快速开始 <a class="header-anchor" href="#gtdamage-快速开始" aria-label="Permalink to &quot;GTDamage 快速开始&quot;">​</a></h1><p>GTDamage 用来显示 RPG 伤害数字和怪物血条。<br> 它能让玩家直观看到伤害、暴击、伤害类型和怪物剩余血量。</p><h2 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h2><ol><li>安装 GTCore。</li><li>安装属性插件，例如 AttributePlus、CraneAttribute 或 SX-Attribute。</li><li>根据显示方案安装 Adyeshach、ProtocolLib 或 PacketEvents。</li><li>放入 GTDamage。</li><li>启动生成配置。</li><li>打怪测试显示。</li></ol><h2 id="最小测试" tabindex="-1">最小测试 <a class="header-anchor" href="#最小测试" aria-label="Permalink to &quot;最小测试&quot;">​</a></h2><ol><li>先关闭复杂字体图。</li><li>使用普通文本显示。</li><li>打一只原版怪物。</li><li>确认出现伤害数字。</li><li>再接入属性插件和字体图。</li></ol><h2 id="常见显示方式" tabindex="-1">常见显示方式 <a class="header-anchor" href="#常见显示方式" aria-label="Permalink to &quot;常见显示方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>说明</th></tr></thead><tbody><tr><td>Adyeshach</td><td>适合已经安装 Ady 的服务器</td></tr><tr><td>ProtocolLib 发包</td><td>适合需要兼容显示</td></tr><tr><td>原版 ArmorStand</td><td>兜底方案</td></tr><tr><td>TextDisplay</td><td>高版本可用</td></tr></tbody></table><h2 id="配置建议" tabindex="-1">配置建议 <a class="header-anchor" href="#配置建议" aria-label="Permalink to &quot;配置建议&quot;">​</a></h2><p>伤害显示是高频功能，要注意性能：</p><ul><li>控制显示范围。</li><li>控制每秒生成数量。</li><li>避免所有玩家都看到所有伤害。</li><li>怪物血条不要每 tick 刷新。</li><li>没必要的 debug 关闭。</li></ul><h2 id="检查点" tabindex="-1">检查点 <a class="header-anchor" href="#检查点" aria-label="Permalink to &quot;检查点&quot;">​</a></h2><ul><li>属性插件是否正常计算伤害。</li><li>GTDamage 是否捕获到伤害事件。</li><li>当前 provider 是否可用。</li><li>显示范围是否包含玩家。</li><li>是否被其他血条插件覆盖。</li></ul>',13)])])}const b=t(r,[["render",d]]);export{u as __pageData,b as default};
